INSERT INTO `a_tn1_root_tmp` VALUES (11,'15c3ada6d3','cache_html',1530631161,'admin_db_root','DB愿?━ 醫뚯륫硫붾돱',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'\r\n\r\n\r\n\r\n\r\n<HTML>\r\n<HEAD>\r\n<base target=\'TnTadmiN_sub_base\'>\r\n <meta http-equiv=\'Content-Type\' content=\'text/html; charset=euc-kr\' /> <meta http-equiv=\'cache-control\' content=\'no-cache\'>\r\n<meta http-equiv=\'pragma\' content=\'no-cache\'>\r\n<TITLE>?뚰겕?명듃PHP</TITLE>\r\n\r\n<STYLE TYPE=text/css>\r\n	\r\n	body,td,input,textarea,select,div{font-size:9pt; font-family:援대┝,Tahoma; color:#333333;}\r\n	body,textarea{overflow:auto;}\r\n	a,label{cursor:pointer;}\r\n\r\n	img{border-width:0;}\r\n	.hand{cursor:pointer;}\r\n	.w_text{border:1px solid #777777;}\r\n	.w_text2{border:1px solid #8CB3E4;}\r\n\r\n	.hr_line{background-color:#f5f5f5; height:1px; padding:0;}\r\n	.exp_text{color:#999999;}\r\n	.table_css{background-color:#ffffff;}\r\n	.sub_title{color:#000000; font-weight:bold; background-color:#f2f2f2;  padding:3px; padding-top:5px; padding-left:5px; background-image:url(\"./img/admin/backline.gif\");}\r\n	.f8pt{font-size:8pt; font-family:Tahoma,verdana;}\r\n	.page_number{color:#444444; font-size:8pt; font-family:Tahoma,援대┝; border:1px solid #dddddd; background-color:#ffffff;  padding-left:3px; padding-right:2px; margin:2px;} /*湲?ぉ濡??섏씠吏?踰덊샇*/\r\n	A:link {text-decoration: none;}\r\n	A:visited {text-decoration: none;}\r\n	A:hover {text-decoration:underline; color:#ff5555;}\r\n\r\n		.i_bname{font-size:8pt; font-family:Tahoma,verdana,?뗭?;}\r\n		.h_name{color:#00A1E4; font-size:9pt; font-family:援대┝; letter-spacing:-1px;}\r\n		.h_name2{color:#DE6C6C; font-size:9pt; font-family:援대┝; letter-spacing:-1px;}\r\n		.i_no{color:#1BA1D3; font-size:7pt; font-family:Tahoma,verdana; font-weight:bold;}\r\n		.i_no2{color:#0196FF; font-size:7pt; font-family:Tahoma,verdana; font-weight:bold;}\r\n</style>\r\n\r\n<SCRIPT LANGUAGE=\"JavaScript\">\r\n\r\n\r\nfunction DIV_menu_open(is_div){\r\n	is_div=document.getElementById(is_div);\r\n	if(is_div.style.display==\'none\') is_div.style.display=\'inline\';\r\n	else is_div.style.display=\'none\';\r\n}\r\n\r\n// 怨듯넻?ㅽ겕由쏀듃\r\n	// 遺?씪?곗? ?곷떒 硫붾돱,踰꾪듉 \'?녿뒗\' ?덈룄?고뙘?낆갹 ?닿린\r\n	function OpenWin_smart(Url,Target,Xsize,Ysize,left_is,top_is,Scroll,Resize){\r\n		if(Xsize==null)Xsize=500;\r\n		if(Ysize==null)Xsize=450;\r\n		if(Resize != \'no\' && Resize != 0 ) Resize=1;\r\n		if(left_is==0)left_is=40;\r\n		if(top_is==0)top_is=30;\r\n		smart_Browser=window.open(Url,Target,\'width=\'+Xsize+\',height=\'+Ysize + \',left=\' +left_is+ \',top=\' +top_is+ \',scrollbars=\'+Scroll+\',resizable=\'+Resize+\',status=0\');\r\n		smart_Browser.focus();\r\n	}\r\n\r\n\r\n</SCRIPT>\r\n</HEAD>\r\n<body text=#000000 link=\'#000000\' alink=\'red\' vlink=\'#000000\' topmargin=0 rightmargin=0 leftmargin=0 style=\'padding-left:3; line-height:130%;\'>\r\n\r\n\r\n<table  width=\'100%\' cellpadding=3 cellspacing=0 border=0 bgcolor=\'#f2f2f2\' background=\"./img/admin/backline3.gif\">\r\n	<tr>\r\n		<td style=\"color:#000000; padding:3; padding-top:5; padding-left:2;\">\r\n			<a href=\"/tn/admin.php?dir_to=top_db&item=db_table_all&tablePrintSet=1\"><img src=\'./img/admin/arow3.gif\' align=right><img src=\'./img/admin/square.gif\' align=absmiddle> ?뚰겕?명듃 ?뚯씠釉??꾩껜紐⑸줉</a>\r\n		</td>\r\n	</tr>\r\n</table>\r\n\r\n<br>\r\n\r\n<!--root-->\r\n<b>1</b>, <img src=\'./img/admin/globe.gif\' align=absmiddle>\r\n<a href=\'javascript:void(0)\' onclick=\"DIV_menu_open(\'div_R\')\">Root 愿?━ ?뚯씠釉?<font color=#cc0000>4</font>)</a><br>\r\n<div id=\'div_R\' class=i_bname style=\'display:none;\'>\r\n&nbsp;&nbsp; <img src=\'./img/admin/look.gif\' align=absmiddle> <a href=\'/tn/admin.php?dir_to=top_db&item=db_table_index&table_name=a_tn1_root_ad\'><font color=#1CA89C><b>a_tn1_root_ad</b></font></a><br>&nbsp;&nbsp; <img src=\'./img/admin/look.gif\' align=absmiddle> <a href=\'/tn/admin.php?dir_to=top_db&item=db_table_index&table_name=a_tn1_root_cnt\'><font color=#1CA89C><b>a_tn1_root_cnt</b></f